func TestBuildReviewPrompt_RankedDiffInclusion(t *testing.T) {
	caps := testCaps()
	caps.MaxDiffBytes = 1 << 20 // generous; ranking matters, not clamping
	caps.MaxInlinedFileBytes = 1 << 20
	caps.MaxPromptBytes = 1 << 20

